import React, { createContext, useContext, useState, useEffect } from 'react';
import { getCurrentWindow } from '@tauri-apps/api/window';

export type ThemePreference = 'system' | 'light' | 'dark';
export type ComputedTheme = 'light' | 'dark';

interface ThemeContextType {
  themePref: ThemePreference;
  computedTheme: ComputedTheme;
  setThemePref: (pref: ThemePreference) => void;
}

export const ThemeContext = createContext<ThemeContextType | null>(null);

function getSystemTheme(): ComputedTheme {
  if (typeof window !== 'undefined' && window.matchMedia) {
    return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
  }
  return 'dark'; // Fallback default
}

export const ThemeProvider = ({ children }: { children: React.ReactNode }) => {
  const [themePref, setThemePrefState] = useState<ThemePreference>(() => {
    const stored = localStorage.getItem('vajra-theme-pref') as ThemePreference;
    return stored || 'system';
  });

  const [computedTheme, setComputedTheme] = useState<ComputedTheme>(() => {
    return themePref === 'system' ? getSystemTheme() : themePref;
  });

  // Recompute actual theme whenever preference changes
  useEffect(() => {
    const actual = themePref === 'system' ? getSystemTheme() : themePref;
    setComputedTheme(actual);
  }, [themePref]);

  // Apply computed theme to DOM and Tauri Window
  useEffect(() => {
    const root = document.documentElement;
    // Temporarily disable transition to prevent flash on theme init
    root.style.setProperty('--transition-slow', '0ms');
    if (computedTheme === 'dark') {
      root.classList.add('dark');
      root.classList.remove('light');
      root.style.colorScheme = 'dark';
    } else {
      root.classList.add('light');
      root.classList.remove('dark');
      root.style.colorScheme = 'light';
    }
    // Sync to the key read by the inline script in index.html
    localStorage.setItem('vajra-theme', computedTheme);
    // Re-enable transitions after a brief paint tick
    requestAnimationFrame(() => {
      requestAnimationFrame(() => {
        root.style.removeProperty('--transition-slow');
      });
    });

    // Attempt to set native window theme if API is available
    try {
      getCurrentWindow().setTheme(computedTheme);
    } catch (e) {
      console.warn("Failed to set native window theme", e);
    }
  }, [computedTheme]);

  // Listen to OS theme changes if 'system' is selected
  useEffect(() => {
    const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');
    const handleChange = (e: MediaQueryListEvent) => {
      if (themePref === 'system') {
        setComputedTheme(e.matches ? 'dark' : 'light');
      }
    };

    // Modern API
    if (mediaQuery.addEventListener) {
      mediaQuery.addEventListener('change', handleChange);
      return () => mediaQuery.removeEventListener('change', handleChange);
    } 
    // Fallback for older WebKit
    else if (mediaQuery.addListener) {
      mediaQuery.addListener(handleChange);
      return () => mediaQuery.removeListener(handleChange);
    }
  }, [themePref]);

  // Listen for storage events to sync themes across multiple WebviewWindows
  useEffect(() => {
    const handleStorage = (e: StorageEvent) => {
      if (e.key === 'vajra-theme-pref' && e.newValue) {
        setThemePrefState(e.newValue as ThemePreference);
      }
    };
    window.addEventListener('storage', handleStorage);
    return () => window.removeEventListener('storage', handleStorage);
  }, []);

  const setThemePref = (pref: ThemePreference) => {
    setThemePrefState(pref);
    localStorage.setItem('vajra-theme-pref', pref);
    // Note: storage events don't fire in the window that triggered them,
    // so we update our own state directly above.
  };

  return (
    <ThemeContext.Provider value={{ themePref, computedTheme, setThemePref }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) throw new Error("useTheme must be used within a ThemeProvider");
  return context;
};

import React, { useState, useEffect } from 'react';
// eslint-disable-next-line @typescript-eslint/no-unused-vars
import { X, Lock, Link as LinkIcon, Folder, HardDriveDownload, Search, Activity, Box, Download, FileCode2 } from 'lucide-react';
import { api, fmtBytes } from '../../api';
import { open } from '@tauri-apps/plugin-dialog';
// eslint-disable-next-line @typescript-eslint/no-unused-vars
import { cn } from '../../utils';

export default function AddUrlDialog({
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  downloads = [], initialUrl = '', onClose, onOk,
// eslint-disable-next-line @typescript-eslint/no-explicit-any
}: any) {
  const [url, setUrl] = useState(initialUrl);
  const [useAuth, setUseAuth] = useState(false);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [maxConnections, setMaxConnections] = useState(8);
  const [speedLimitKb, setSpeedLimitKb] = useState('');
  const [outputDir, setOutputDir] = useState('');
  const [expectedHash, setExpectedHash] = useState('');
  const [autoExtract, setAutoExtract] = useState(false);
  const [postProcessingScript, setPostProcessingScript] = useState('');
  const [startLater, setStartLater] = useState(false);
  const [scheduleAt, setScheduleAt] = useState('');
  const [queueType, setQueueType] = useState('Standard');
  const [syncIntervalMins, setSyncIntervalMins] = useState(60);
  const [inspectState, setInspectState] = useState<'idle'|'loading'|'success'|'error'>('idle');
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const [inspectData, setInspectData] = useState<any>(null);
  const [filename, setFilename] = useState('');

  useEffect(() => {
    api.config().then(cfg => {
      if (cfg?.default_max_connections) setMaxConnections(cfg.default_max_connections);
    }).catch(console.error);
  }, []);

  // Auto-fill credentials
  useEffect(() => {
    if (!url.trim()) return;
    try {
      const host = new URL(url.trim()).hostname.toLowerCase();
      const saved = localStorage.getItem('vajra_site_logins');
      if (saved) {
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const match = JSON.parse(saved).find((l: any) =>
          host === l.host.toLowerCase() || host.endsWith('.' + l.host.toLowerCase())
        );
        if (match) { setUseAuth(true); setUsername(match.user); setPassword(match.pass); }
      }
    } catch { /* ignore */ }
  }, [url]);

  // Debounced inspect
  useEffect(() => {
    if (!url.trim() || !url.startsWith('http')) { setInspectState('idle'); setInspectData(null); return; }
    const t = setTimeout(async () => {
      setInspectState('loading');
      try {
        const res = await api.inspect(url.trim());
        setInspectData(res);
        if (res.filename) setFilename(res.filename);
        setInspectState('success');
      } catch { setInspectState('error'); }
    }, 800);
    return () => clearTimeout(t);
  }, [url]);

  const handleOk = () => {
    if (!url.trim()) return;
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const payload: any = {
      url: url.trim(),
      filename: filename.trim() || undefined,
      output_dir: outputDir.trim() || undefined,
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      max_connections: parseInt(maxConnections as any, 10) || 8,
      expected_hash: expectedHash.trim() || undefined,
      auto_extract: autoExtract,
      post_processing_script: postProcessingScript.trim() || undefined,
      speed_limit_bps: speedLimitKb ? parseInt(speedLimitKb, 10) * 1024 : 0,
      schedule_at: scheduleAt ? Math.floor(new Date(scheduleAt).getTime() / 1000) : undefined,
      _startLater: startLater,
      queue_type: queueType,
      sync_interval_secs: queueType === 'Synchronization' ? syncIntervalMins * 60 : 0,
    };
    if (useAuth && username && password) {
      payload.headers = { Authorization: `Basic ${btoa(`${username}:${password}`)}` };
    }
    onOk(payload);
  };

  const handleBrowse = async () => {
    try {
      const selected = await open({ directory: true, multiple: false });
      if (selected) setOutputDir(selected as string);
    } catch (err) { console.error('Folder picker not available', err); }
  };

  /* ---- Field helpers ---- */
  const Label = ({ children }: { children: React.ReactNode }) => (
    <span className="form-label">{children}</span>
  );
  const CheckRow = ({ checked, onChange, label }: { checked: boolean; onChange: (v: boolean) => void; label: string }) => (
    <label className="flex items-center gap-2" style={{ cursor: 'default', fontSize: 'var(--text-sm-size)', color: 'var(--color-text-2)' }}>
      <input
        type="checkbox"
        checked={checked}
        onChange={e => onChange(e.target.checked)}
        style={{ accentColor: 'var(--color-brand)', width: 13, height: 13, cursor: 'default' }}
      />
      {label}
    </label>
  );

  return (
    <div className="dialog-overlay" onClick={onClose}>
      <div className="dialog-panel" style={{ width: 580 }} onClick={e => e.stopPropagation()}>
        {/* Header */}
        <div className="dialog-header">
          <div className="dialog-header-title">
            <LinkIcon size={16} />
            New Download Task
          </div>
          <button className="btn-icon" onClick={onClose} title="Close">
            <X size={15} />
          </button>
        </div>

        {/* Body */}
        <div className="dialog-body" style={{ gap: 'var(--sp-4)' }}>

          {/* URL */}
          <div className="card-subtle" style={{ padding: 'var(--sp-3) var(--sp-4)' }}>
            <div className="flex items-center justify-between mb-2">
              <Label>Download URL</Label>
              <span style={{ fontSize: 'var(--text-xs-size)' }}>
                {inspectState === 'loading' && (
                  <span style={{ color: 'var(--color-info)', display: 'flex', alignItems: 'center', gap: 4 }}>
                    <Search size={10} className="animate-pulse" /> Inspecting…
                  </span>
                )}
                {inspectState === 'error' && (
                  <span style={{ color: 'var(--color-error)' }}>Inspect failed</span>
                )}
                {inspectState === 'success' && (
                  <span style={{ color: 'var(--color-success)', display: 'flex', alignItems: 'center', gap: 4 }}>
                    <Activity size={10} /> Verified
                  </span>
                )}
              </span>
            </div>
            <input
              type="text"
              className="input-field"
              value={url}
              onChange={e => setUrl(e.target.value)}
              placeholder="https://"
              autoFocus
            />
            {inspectState === 'success' && inspectData && (
              <div className="flex gap-4 mt-2 pt-2" style={{ borderTop: '1px solid var(--color-border-subtle)', fontSize: 'var(--text-xs-size)', color: 'var(--color-text-3)' }}>
                <span style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
                  <HardDriveDownload size={10} style={{ color: 'var(--color-brand)' }} />
                  {inspectData.total_bytes ? fmtBytes(inspectData.total_bytes) : 'Unknown'}
                </span>
                <span style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
                  <Box size={10} style={{ color: 'var(--color-brand)' }} />
                  {inspectData.content_type || 'Unknown'}
                </span>
                <span style={{ display: 'flex', alignItems: 'center', gap: 4, color: inspectData.accepts_ranges ? 'var(--color-success)' : 'var(--color-warning)', fontWeight: 600 }}>
                  <Activity size={10} />
                  {inspectData.accepts_ranges ? 'Resume Supported' : 'No Resume'}
                </span>
              </div>
            )}
          </div>

          {/* File Name + Save Dir */}
          <div className="grid grid-cols-2 gap-3">
            <div className="form-group">
              <Label>File Name</Label>
              <input type="text" className="input-field" value={filename} onChange={e => setFilename(e.target.value)} placeholder="Auto-detect" />
            </div>
            <div className="form-group">
              <Label>Save Directory</Label>
              <div className="flex gap-1.5">
                <input type="text" className="input-field" value={outputDir} onChange={e => setOutputDir(e.target.value)} placeholder="System default" />
                <button className="btn-secondary flex-shrink-0 gap-1.5" style={{ padding: '0 10px' }} onClick={handleBrowse} title="Browse">
                  <Folder size={14} />
                </button>
              </div>
            </div>
          </div>

          {/* Engine Parameters */}
          <div className="card-subtle" style={{ padding: 'var(--sp-3) var(--sp-4)' }}>
            <div className="section-title mb-2">Engine Parameters</div>
            <div className="grid grid-cols-3 gap-3 mb-3">
              <div className="form-group">
                <Label>Threads</Label>
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                <select className="select-field" value={maxConnections} onChange={e => setMaxConnections(e.target.value as any)}>
                  {[1,2,4,8,16,32,64].map(n => <option key={n} value={n}>{n}{n===64?' (Unsafe)':n===32?' (Extreme)':''}</option>)}
                </select>
              </div>
              <div className="form-group">
                <Label>Speed Limit (KB/s)</Label>
                <input type="number" className="input-field" value={speedLimitKb} onChange={e => setSpeedLimitKb(e.target.value)} placeholder="0 = Unlimited" />
              </div>
              <div className="form-group">
                <Label>Expected Hash</Label>
                <input type="text" className="input-field" value={expectedHash} onChange={e => setExpectedHash(e.target.value)} placeholder="sha256:…" />
              </div>
            </div>
            <div className="grid grid-cols-2 gap-3 pt-3" style={{ borderTop: '1px solid var(--color-border-subtle)' }}>
              <div className="flex flex-col gap-2">
                <CheckRow checked={useAuth} onChange={setUseAuth} label="Basic Authentication" />
                {useAuth && (
                  <div className="flex gap-1.5 animate-fade-in">
                    <input type="text" className="input-field" value={username} onChange={e => setUsername(e.target.value)} placeholder="Username" />
                    <input type="password" className="input-field" value={password} onChange={e => setPassword(e.target.value)} placeholder="Password" />
                  </div>
                )}
              </div>
              <div className="form-group">
                <Label>Post-Process Script</Label>
                <input type="text" className="input-field" value={postProcessingScript} onChange={e => setPostProcessingScript(e.target.value)} placeholder="C:\scripts\run.bat" />
              </div>
            </div>
            <div className="grid grid-cols-2 gap-3 pt-3 mt-1" style={{ borderTop: '1px solid var(--color-border-subtle)' }}>
              <div className="form-group">
                <Label>Queue Type</Label>
                <select className="select-field" value={queueType} onChange={e => setQueueType(e.target.value)}>
                  <option value="Standard">Standard</option>
                  <option value="Synchronization">Synchronization (Auto-Sync)</option>
                </select>
              </div>
              {queueType === 'Synchronization' && (
                <div className="form-group animate-fade-in">
                  <Label>Sync Interval (Minutes)</Label>
                  <input type="number" className="input-field" value={syncIntervalMins} onChange={e => setSyncIntervalMins(parseInt(e.target.value) || 60)} />
                </div>
              )}
            </div>
          </div>

          {/* Quick Toggles + Schedule */}
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <CheckRow checked={startLater} onChange={setStartLater} label="Queue Paused" />
              <CheckRow checked={autoExtract} onChange={setAutoExtract} label="Auto-Extract" />
            </div>
            <div className="flex items-center gap-2">
              <span className="form-label">Schedule</span>
              <input
                type="datetime-local"
                className="input-field"
                style={{ width: 'auto' }}
                value={scheduleAt}
                onChange={e => setScheduleAt(e.target.value)}
              />
            </div>
          </div>
        </div>

        {/* Footer */}
        <div className="dialog-footer">
          <button className="btn-secondary" onClick={onClose}>Cancel</button>
          <button className="btn-primary flex items-center gap-2" onClick={handleOk} disabled={!url.trim()}>
            <Download size={14} />
            Add Download
          </button>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { 
  X, Settings, FileBox, Wifi, HardDriveDownload, 
  Network, Lock, Phone, MonitorPlay, FileCheck2, 
  Globe, Fingerprint, Activity, Server, AlertCircle, 
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  Check, Save, Trash2, FolderOpen
} from 'lucide-react';
import { cn } from '../../utils';
import { api } from '../../api';
import { open } from '@tauri-apps/plugin-dialog';
import { useTheme, ThemePreference } from '../../ThemeContext';

export default function OptionsDialog({ onClose }: { onClose: () => void }) {
  const [activeTab, setActiveTab] = useState('General');
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const [config, setConfig] = useState<any>(null);
  const [deletePreference, setDeletePreference] = useState(() => localStorage.getItem('vajra_delete_preference'));
  const [isSaving, setIsSaving] = useState(false);

  const { themePref, setThemePref } = useTheme();

  // Site Logins
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const [logins, setLogins] = useState<any[]>([]);

  const [newLoginHost, setNewLoginHost] = useState('');
  const [newLoginUser, setNewLoginUser] = useState('');
  const [newLoginPass, setNewLoginPass] = useState('');

  // Dialup Settings
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const [dialup, setDialup] = useState<any>(() => {
    try {
      const saved = localStorage.getItem('vajra_dialup_settings');
      if (saved) return JSON.parse(saved);
    } catch(e) { /* ignore */ }
    return { connectionName: '', username: '', password: '', redialCount: 5 };
  });

  // Sound Config
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const [soundConfig, setSoundConfig] = useState<any>(() => {
    try {
      const saved = localStorage.getItem('vajra_sounds_config');
      if (saved) return JSON.parse(saved);
    } catch(e) { /* ignore */ }
    return { onComplete: true, onFail: false, onQueueStart: false };
  });

  useEffect(() => {
    const loadConfig = () => api.config().then(setConfig).catch(e => { console.error("Config load error:", e); setConfig({ _error: e.toString() }); });
    loadConfig();
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (window as any)._retryConfig = loadConfig;
    api.getVault().then(setLogins).catch(console.error);
  }, []);

  useEffect(() => {
    localStorage.setItem('vajra_dialup_settings', JSON.stringify(dialup));
  }, [dialup]);

  useEffect(() => {
    localStorage.setItem('vajra_sounds_config', JSON.stringify(soundConfig));
  }, [soundConfig]);

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const updateConfig = (updates: any) => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    setConfig((prev: any) => {
      const next = { ...prev, ...updates };
      setIsSaving(true);
      api.setConfig(next)
        .then(() => setTimeout(() => setIsSaving(false), 500))
        .catch(console.error);
      return next;
    });
  };

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const updateProxy = (updates: any) => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    setConfig((prev: any) => {
      const next = { ...prev, proxy: { ...prev.proxy, ...updates } };
      setIsSaving(true);
      api.setConfig(next)
        .then(() => setTimeout(() => setIsSaving(false), 500))
        .catch(console.error);
      return next;
    });
  };

  const Toggle = ({ active, onClick, label }: { active: boolean; onClick: () => void; label?: string }) => (
    <label className="flex items-center justify-between" style={{ cursor: 'default' }}>
      {label && <span style={{ fontSize: 'var(--text-sm-size)', fontWeight: 500, color: 'var(--color-text-1)' }}>{label}</span>}
      <div
        onClick={e => { e.preventDefault(); onClick(); }}
        style={{
          position: 'relative', display: 'inline-flex', height: 20, width: 36,
          borderRadius: 10, transition: 'background-color var(--transition-normal)',
          backgroundColor: active ? 'var(--color-brand)' : 'var(--color-border)',
          cursor: 'default', flexShrink: 0,
        }}
      >
        <span style={{
          position: 'absolute', top: 2, left: 2, width: 16, height: 16,
          borderRadius: '50%', backgroundColor: 'var(--color-surface)',
          boxShadow: 'var(--shadow-sm)', transition: 'transform var(--transition-normal)',
          transform: active ? 'translateX(16px)' : 'translateX(0)',
        }} />
      </div>
    </label>
  );

  const tabs = [
    { id: 'General', icon: Settings, desc: 'Startup, browser & dialogs' },
    { id: 'File Types', icon: FileBox, desc: 'Auto-downloads & blacklists' },
    { id: 'Connection', icon: Wifi, desc: 'Limits & speed tuning' },
    { id: 'Downloads', icon: HardDriveDownload, desc: 'Directories & actions' },
    { id: 'Automation & Security', icon: Activity, desc: 'Scheduling & AV' },
    { id: 'Proxy / Socks', icon: Network, desc: 'Proxy configuration' },
    { id: 'Site Logins', icon: Lock, desc: 'Saved credentials' },
    { id: 'Dial-up', icon: Phone, desc: 'VPN & Dial-up settings' }
  ];

  const handleBrowseFolder = async (field: string) => {
    try {
      const selected = await open({ directory: true });
      if (selected) {
        updateConfig({ [field]: selected });
      }
    } catch (err) {
      console.error("Folder picker not available", err);
    }
  };

  const handleBrowseFile = async (field: string) => {
    try {
      const selected = await open({ directory: false });
      if (selected) {
        updateConfig({ [field]: selected });
      }
    } catch (err) {
      console.error("File picker not available", err);
    }
  };

  const addLogin = async () => {
    if (newLoginHost.trim() && newLoginUser.trim() && newLoginPass.trim()) {
      try {
        const added = await api.addVault({
          domain: newLoginHost.trim(),
          username: newLoginUser.trim(),
          password: newLoginPass.trim()
        });
        setLogins(prev => [...prev, added].sort((a, b) => a.domain.localeCompare(b.domain)));
        setNewLoginHost('');
        setNewLoginUser('');
        setNewLoginPass('');
      } catch (err) {
        console.error("Failed to add site login", err);
      }
    }
  };

  const removeLogin = async (id: string) => {
    try {
      await api.deleteVault(id);
      setLogins(prev => prev.filter(l => l.id !== id));
    } catch (err) {
      console.error("Failed to remove site login", err);
    }
  };

  // Modern Input Component
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const ConfigInput = ({ label, value, onChange, placeholder, type = "text", icon: Icon }: any) => (
    <div className="flex flex-col gap-1.5 w-full">
      <label className="text-xs font-semibold text-[var(--color-text-2)] uppercase tracking-wider">{label}</label>
      <div className="relative">
        {Icon && <Icon className="absolute left-3 top-1/2 -translate-y-1/2 text-[var(--color-text-3)]" size={14} />}
        <input 
          type={type}
          placeholder={placeholder}
          className={cn(
            "w-full bg-[var(--color-surface-elevated)] border border-border/50 rounded-lg px-3 py-2 text-sm text-[var(--color-text-1)]",
            "focus:outline-none focus:ring-2 focus:ring-[var(--color-brand-dim)] focus:border-[var(--color-brand)] transition-all placeholder:text-[var(--color-text-4)]",
            Icon ? "pl-9" : ""
          )}
          value={value}
          onChange={onChange}
        />
      </div>
    </div>
  );

  return (
    <div className="dialog-overlay" onClick={onClose}>
      <div className="dialog-panel" style={{ width: 860, height: 580, maxWidth: '92vw', maxHeight: '90vh', flexDirection: 'column' }} onClick={e => e.stopPropagation()}>

        {/* Header */}
        <div className="dialog-header" style={{ padding: '12px 20px' }}>
          <div className="dialog-header-title" style={{ gap: 10 }}>
            <div style={{ backgroundColor: 'var(--color-brand-dim)', padding: 8, borderRadius: 'var(--radius-lg)', color: 'var(--color-brand)', display: 'flex' }}>
              <Settings size={18} />
            </div>
            <div>
              <div style={{ fontWeight: 700, fontSize: 'var(--text-base-size)', color: 'var(--color-text-1)' }}>Settings</div>
